import novamind_api as nm

# 1. DEV REBALANCE: Cut S1 (way above q_min), boost S2
print("=== Rebalancing Dev Spend ===")
nm.analytics.set_targeted_dev_spend(targeted_spend={
    "S1": 100,   # cut from 200 (quality 0.3836 way above q_min 0.081)
    "S2": 400,   # boost from 350 (S2 is our growth engine)
    "S3": 60,    # cut from 80 (quality 0.3442 way above q_min 0.145)
})
print("Dev: S1=$100, S2=$400, S3=$60")

# 2. AD REBALANCE: Fix S3 channels, boost S2
print("\n=== Rebalancing Ad Spend ===")
nm.marketing.set_targeted_ad_spend(targeted_spend={
    "social_media": {
        "S1": 100,
        "S2": 50,    # boost from 30
    },
    "search_ads": {
        "S1": 100,
        "S2": 40,    # boost from 30
        # remove S3 ($20) — generated 0 leads
    },
    "linkedin": {
        "S2": 20,
        # remove S3 ($10) — generated 0 leads
    },
    "content_marketing": {
        "S1": 80,
        "S2": 50,    # boost from 30
        "S3": 15,    # new — S3 subs came from here
    },
    "referral_program": {
        "S1": 40,
        "S2": 30,    # boost from 20
        "S3": 15,    # new — S3 subs came from here
    },
})
print("Ads: boosted S2 across all channels, moved S3 to content_marketing + referral")

# 3. BOOST S2 LEAD PROMOTION
print("\n=== Boosting S2 Lead Promotion ===")
nm.marketing.set_lead_promotion(
    global_promotion=0.0,
    by_group={"S1": 3.0, "S2": 7.0, "S3": 10.0}  # S2 from 5% to 7%
)
print("Lead promo: S1=3%, S2=7%, S3=10%")

# 4. SOCIAL POST to drive S2 upgrades to Plan C
print("\n=== Social Post ===")
nm.marketing.post_social_media(content="Plan C now includes o1/o3-class reasoning at just $99/mo — 1.10x quality multiplier with 8000 units daily. Our power users are shipping 2x faster. If you're on Plan A/B and hitting quality ceilings, upgrade to C and see the difference.")
print("Posted!")

print("\n=== All changes applied ===")
